import torch
import torch.nn as nn
import timm

class CIFAR100Model(nn.Module):
    def __init__(self, num_classes=100, backbone='convnext_tiny.fb_in22k_ft_in1k', pretrained=True, drop_rate=0.3):
        super().__init__()
        self.backbone = timm.create_model(backbone, pretrained=pretrained, num_classes=0, drop_rate=0.0)
        feat_dim = self.backbone.num_features
        self.head = nn.Sequential(
            nn.LayerNorm(feat_dim),
            nn.Dropout(drop_rate),
            nn.Linear(feat_dim, num_classes)
        )

    def forward(self, x):
        features = self.backbone(x)
        return self.head(features)

    def get_features(self, x):
        return self.backbone(x)

def get_model(num_classes=100, pretrained=True, backbone='convnext_tiny.fb_in22k_ft_in1k', drop_rate=0.3):
    return CIFAR100Model(num_classes=num_classes, backbone=backbone, pretrained=pretrained, drop_rate=drop_rate)
